import { Link, useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";
import { clearAuth, getAuth } from "../utils/auth";

export default function Navbar() {
  const navigate = useNavigate();
  const [auth, setAuthState] = useState(getAuth());

  useEffect(() => {
    const refresh = () => setAuthState(getAuth());
    window.addEventListener("auth-change", refresh);
    window.addEventListener("storage", refresh);

    return () => {
      window.removeEventListener("auth-change", refresh);
      window.removeEventListener("storage", refresh);
    };
  }, []);

  const logout = () => {
    clearAuth();
    navigate("/login");
  };

  const isLogged = !!auth?.token;
  const role = auth?.role; // admin | manager | staff | user

  const isCustomer = isLogged && role === "user";
  const isStaff = isLogged && ["staff", "manager", "admin"].includes(role);
  const isManager = isLogged && ["manager", "admin"].includes(role);
  const isAdmin = isLogged && role === "admin";

  const navStyle = {
    padding: 14,
    background: "#1f1f1f",
    color: "#fff",
    display: "flex",
    alignItems: "center",
    gap: 16,
    fontWeight: 500,
  };

  const linkStyle = {
    color: "#fff",
    textDecoration: "none",
  };

  const btnStyle = {
    padding: "6px 12px",
    cursor: "pointer",
    border: "1px solid #555",
    background: "#111",
    color: "#fff",
    borderRadius: 8,
  };

  return (
    <nav style={navStyle}>
      {/* Left Side */}
      <Link to="/" style={linkStyle}>Home</Link>
      <Link to="/vehicles" style={linkStyle}>Vehicles</Link>

      <div style={{ flex: 1 }} />

      {/* Not Logged */}
      {!isLogged && (
        <>
          <Link to="/login" style={linkStyle}>Login</Link>
          <Link to="/register" style={linkStyle}>Register</Link>
        </>
      )}

      {/* Customer */}
      {isCustomer && (
        <>
          <Link to="/book-appointment" style={linkStyle}>Book</Link>
          <Link to="/my-appointments" style={linkStyle}>My Appointments</Link>
          <button onClick={logout} style={btnStyle}>Logout</button>
        </>
      )}

      {/* Staff / Manager / Admin */}
      {isStaff && (
        <>
          <Link to="/appointments" style={linkStyle}>Appointments</Link>
          <Link to="/documents" style={linkStyle}>Documents</Link>

          {/* Manager + Admin */}
          {isManager && (
            <>
              <Link to="/sales" style={linkStyle}>Sales</Link>
            </>
          )}

          {/* Admin only */}
          {isAdmin && (
            <>
            <Link to="/admin/staff" style={linkStyle}>Staff List</Link> 
            </>
          )}

          <button onClick={logout} style={btnStyle}>Logout</button>
        </>
      )}
    </nav>
  );
}
